changeSet.sql:
UPDATE clinlims.test SET name = REPLACE(name, 'Sécrétion cervical -', 'Sécrétion cervicale -'), description = REPLACE(description, 'Sécrétion cervical -', 'Sécrétion cervicale -'), lastupdated = now() WHERE name LIKE '%Sécrétion cervical -%';
UPDATE clinlims.localization SET french = REPLACE(french, 'Sécrétion cervical -', 'Sécrétion cervicale -'), lastupdated = now() WHERE french LIKE '%Sécrétion cervical -%';
UPDATE clinlims.localization SET english = REPLACE(english, 'cervical secretion ', 'cervicale secretion ') WHERE english LIKE '%-Bacteria-cervical secretion %';
